240→// ---------------------------------------------------------------------------
241→
242→export type TestUser = {
243→  headers: Record<string, string>;
244→};
245→
246→export async function createTestUser(baseUrl: string, suffix: string): Promise<TestUser> {
247→  const email = `test-${Date.now()}-${suffix}@test.local`;
248→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
249→    method: "POST",
250→    headers: { "Content-Type": "application/json" },
251→    body: JSON.stringify({ name: "Test User", email, password: "test-password-123" }),
252→    redirect: "manual",
253→  });
254→
255→  if (!response.ok) {
256→    const body = await response.text();
257→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
258→  }
259→
260→  const setCookie = response.headers.getSetCookie();
261→  if (!setCookie || setCookie.length === 0) {
262→    throw new Error("Sign-up did not return session cookies");
263→  }
264→
265→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
266→  return { headers: { Cookie: cookieHeader } };
267→}
268→
