          ),
        ),
      },
      "/api/workspaces/:workspaceId/proxy/compliance": {
        GET: withTracing(
          "GET /api/workspaces/:workspaceId/proxy/compliance",
          "GET",
          (request) => auditApiHandlers.handleCompliance(
